use soroban_sdk::{contract, contractimpl, Address, Env, Bytes, Symbol, Vec, Val};

#[contractimpl]
impl SafeBridgeContract {
    // SAFE: invoke_contract with require_auth and .expect
    pub fn safe_transfer(env: Env, admin: Address, target: Address, amount: i128) {
        admin.require_auth();
        let client = Client::new(&env, &target);
        let result = client.transfer(&amount);
        result.unwrap_or_else(|e| panic!("transfer failed"));
    }

    // SAFE: env.invoke_contract with match on result
    pub fn safe_relay(env: Env, contract: Address, func: Bytes, args: Bytes) -> Bytes {
        let result = env.invoke_contract(&contract, &func, &args);
        match result {
            Ok(data) => data,
            Err(_) => panic!("invocation failed"),
        }
    }

    // SAFE: invoke_contract with .expect handling
    pub fn safe_call_external(env: Env, target: Address, method: Symbol, args: Vec<Val>) -> Val {
        env.invoke_contract(&target, &method, &args).expect("external call failed")
    }

    pub fn get_balance(env: Env, address: Address) -> i128 {
        env.storage().instance().get(&address).unwrap_or(0)
    }
}
